//#region src/organon/built-in/trace-lookup.ts
const traceLookupTool = {
	definition: {
		name: "trace_lookup",
		description: "Inspect your own reasoning traces from recent turns.\n\nUSE WHEN:\n- Debugging why a previous action failed or produced unexpected results\n- Understanding your own tool call patterns and timing\n- Checking token usage and model selection for recent turns\n- Reviewing what bootstrap files were loaded\n\nDO NOT USE WHEN:\n- Looking at another agent's traces — only shows your own\n- Current turn info — use session_status instead\n\nTIPS:\n- Filter by 'tools', 'cross-agent', 'usage', or 'all' (default)\n- Shows up to 20 turns back\n- Includes tool call timing for performance analysis",
		input_schema: {
			type: "object",
			properties: {
				turns_back: {
					type: "number",
					description: "How many turns back to look (default 5, max 20)"
				},
				filter: {
					type: "string",
					description: "Optional filter: 'tools', 'cross-agent', 'usage', 'all' (default: all)"
				}
			}
		}
	},
	execute(input, context) {
		const turnsBack = Math.min(input["turns_back"] ?? 5, 20);
		const filter = input["filter"] ?? "all";
		const tracesFile = join(paths.tracesDir(), `${context.nousId}.jsonl`);
		if (!existsSync(tracesFile)) return Promise.resolve(JSON.stringify({
			error: "No traces found",
			file: tracesFile
		}));
		const traces = readFileSync(tracesFile, "utf-8").trim().split("\n").filter(Boolean).slice(-turnsBack).map((line) => {
			try {
				return JSON.parse(line);
			} catch {
				return null;
			}
		}).filter(Boolean);
		if (traces.length === 0) return Promise.resolve(JSON.stringify({ error: "No valid traces found" }));
		const filtered = traces.map((t) => {
			const base = {
				turnSeq: t["turnSeq"],
				model: t["model"],
				timestamp: t["startedAt"],
				durationMs: t["durationMs"]
			};
			if (filter === "tools" || filter === "all") Object.assign(base, { toolCalls: t["toolCalls"]?.map((tc) => ({
				name: tc["name"],
				durationMs: tc["durationMs"],
				isError: tc["isError"],
				inputPreview: String(JSON.stringify(tc["input"]) ?? "").slice(0, 100)
			})) });
			if (filter === "cross-agent" || filter === "all") Object.assign(base, { crossAgentCalls: t["crossAgentCalls"] });
			if (filter === "usage" || filter === "all") Object.assign(base, {
				usage: t["usage"],
				bootstrapFiles: t["bootstrapFiles"],
				degradedServices: t["degradedServices"]
			});
			return base;
		});
		return Promise.resolve(JSON.stringify({
			nousId: context.nousId,
			tracesFound: filtered.length,
			traces: filtered
		}));
	}
};

