function createRecentCorrectionsTool(store) {
	return {
		definition: {
			name: "recent_corrections",
			description: "Review your recent correction and feedback signals to learn from mistakes.\n\nUSE WHEN:\n- Noticing repeated errors in a domain\n- Preparing to attempt a task you've failed at before\n- Self-reflecting on interaction patterns\n\nDO NOT USE WHEN:\n- No relevant correction history exists yet\n\nTIPS:\n- Shows last N interaction signals with timestamps\n- High-confidence corrections are stronger learning signals\n- Pattern detection: multiple corrections in same domain = systematic issue",
			input_schema: {
				type: "object",
				properties: { limit: {
					type: "number",
					description: "Max signals to return (default 30)"
				} }
			}
		},
		execute(input, context) {
			if (!store) return Promise.resolve(JSON.stringify({ error: "Store not available" }));
			const limit = input["limit"] || 30;
			const signals = store.getSignalHistory(context.nousId, limit);
			if (signals.length === 0) return Promise.resolve(JSON.stringify({
				nousId: context.nousId,
				note: "No interaction signals recorded yet",
				signals: []
			}));
			const grouped = {};
			for (const s of signals) grouped[s.signal] = (grouped[s.signal] ?? 0) + 1;
			const corrections = signals.filter((s) => s.signal === "correction");
			const clusters = [];
			let clusterStart = 0;
			for (let i = 1; i < corrections.length; i++) if (new Date(corrections[i - 1].createdAt).getTime() - new Date(corrections[i].createdAt).getTime() > 36e5) {
				if (i - clusterStart > 1) clusters.push({
					count: i - clusterStart,
					timespan: corrections[clusterStart].createdAt
				});
				clusterStart = i;
			}
			if (corrections.length - clusterStart > 1) clusters.push({
				count: corrections.length - clusterStart,
				timespan: corrections[clusterStart].createdAt
			});
			return Promise.resolve(JSON.stringify({
				nousId: context.nousId,
				summary: grouped,
				correctionClusters: clusters.length > 0 ? clusters : void 0,
				signals: signals.map((s) => ({
					signal: s.signal,
					confidence: s.confidence,
					turn: s.turnSeq,
					at: s.createdAt
				}))
			}));
		}
	};
}

