//#region src/organon/built-in/blackboard.ts
function createBlackboardTool(store) {
	return {
		definition: {
			name: "blackboard",
			description: "Read and write shared state visible to all agents. Entries auto-expire.\n\nUSE WHEN:\n- Sharing findings, status, or coordination signals with other agents\n- Checking if another agent has posted relevant context\n- Leaving breadcrumbs for future sessions\n\nDO NOT USE WHEN:\n- Storing long-term facts (use memory/mem0 instead)\n- Private session-scoped data (just use your workspace files)\n\nTIPS:\n- Actions: 'write', 'read', 'list', 'delete'\n- Default TTL is 1 hour; use ttl_seconds to customize\n- Each agent can only update/delete their own entries\n- 'list' shows all active keys across agents",
			input_schema: {
				type: "object",
				properties: {
					action: {
						type: "string",
						description: "Action: 'write', 'read', 'list', 'delete'"
					},
					key: {
						type: "string",
						description: "Blackboard key (required for write/read/delete)"
					},
					value: {
						type: "string",
						description: "Value to write (required for write action)"
					},
					ttl_seconds: {
						type: "number",
						description: "Time-to-live in seconds (default 3600 = 1 hour)"
					}
				},
				required: ["action"]
			}
		},
		execute(input, context) {
			const action = input["action"];
			const key = input["key"];
			const value = input["value"];
			const ttl = input["ttl_seconds"] || 3600;
			switch (action) {
				case "write": {
					if (!key || !value) return Promise.resolve(JSON.stringify({ error: "key and value required for write" }));
					const id = store.blackboardWrite(key, value, context.nousId, ttl);
					return Promise.resolve(JSON.stringify({
						written: true,
						id,
						key,
						ttl_seconds: ttl
					}));
				}
				case "read": {
					if (!key) return Promise.resolve(JSON.stringify({ error: "key required for read" }));
					const entries = store.blackboardRead(key);
					return Promise.resolve(JSON.stringify({
						key,
						entries
					}));
				}
				case "list": {
					const keys = store.blackboardList();
					return Promise.resolve(JSON.stringify({ keys }));
				}
				case "delete": {
					if (!key) return Promise.resolve(JSON.stringify({ error: "key required for delete" }));
					const deleted = store.blackboardDelete(key, context.nousId);
					return Promise.resolve(JSON.stringify({
						deleted,
						key
					}));
				}
				default: return Promise.resolve(JSON.stringify({ error: `Unknown action: ${action}. Use write/read/list/delete.` }));
			}
		}
	};
}

