//#region src/hermeneus/pricing.ts
const PRICING = {
	"claude-opus-4-6": {
		inputPerMTok: 15,
		outputPerMTok: 75,
		cacheReadPerMTok: 1.5,
		cacheWritePerMTok: 18.75
	},
	"claude-sonnet-4-6": {
		inputPerMTok: 3,
		outputPerMTok: 15,
		cacheReadPerMTok: .3,
		cacheWritePerMTok: 3.75
	},
	"claude-sonnet-4-5-20250929": {
		inputPerMTok: 3,
		outputPerMTok: 15,
		cacheReadPerMTok: .3,
		cacheWritePerMTok: 3.75
	},
	"claude-haiku-4-5-20251001": {
		inputPerMTok: .8,
		outputPerMTok: 4,
		cacheReadPerMTok: .08,
		cacheWritePerMTok: 1
	}
};
function resolvePricing(model) {
	if (model) {
		const exact = PRICING[model];
		if (exact) return exact;
		if (model.includes("opus")) return PRICING["claude-opus-4-6"];
		if (model.includes("sonnet")) return PRICING["claude-sonnet-4-6"];
		if (model.includes("haiku")) return PRICING["claude-haiku-4-5-20251001"];
	}
	return PRICING["claude-sonnet-4-6"];
}
function calculateCostBreakdown(usage) {
	const p = resolvePricing(usage.model);
	const inputCost = usage.inputTokens / 1e6 * p.inputPerMTok;
	const outputCost = usage.outputTokens / 1e6 * p.outputPerMTok;
	const cacheReadCost = usage.cacheReadTokens / 1e6 * p.cacheReadPerMTok;
	const cacheWriteCost = usage.cacheWriteTokens / 1e6 * p.cacheWritePerMTok;
	return {
		inputCost,
		outputCost,
		cacheReadCost,
		cacheWriteCost,
		totalCost: inputCost + outputCost + cacheReadCost + cacheWriteCost
	};
}

